def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        usage_ratio = item / capacity
        priority = 100.0
        if usage_ratio > 4:
            priority += 5000 * np.power(usage_ratio, 1.45) - 250 * np.log1p(capacity)
            if capacity > 10:
                priority += 80 * np.sqrt(capacity) * np.cos(capacity / 2) - 60 * np.sin(capacity / 4)
            else:
                priority -= 50 * usage_ratio
            for p in range(1, 6):
                priority += ((-1) ** p) * np.sin(usage_ratio * np.pi * p**1.1) * 20 / p
                if p % 2 == 0 and capacity % p < 0.3:
                    priority += 10 * p
        elif 3 < usage_ratio <= 4:
            delta = usage_ratio - 3
            priority += 3000 * delta**1.7 + 200 * (1 - delta**0.9)
            for q in range(1, 9):
                priority += np.cos(usage_ratio * np.pi * q**1.3) * 25 / q
                if capacity % (q+1) < 0.4:
                    priority -= 15 * q / 2
            if capacity % 3 < 0.7:
                priority += 40 * np.tanh(capacity / 12)
        elif 2 < usage_ratio <= 3:
            priority += 1500 * (usage_ratio - 2) ** 2.2 + 100 * np.sin(capacity * 3)
            for r in range(1, 12):
                power = usage_ratio ** r
                if power < 0.4:
                    priority += power * 30 / r
                    if r % 3 == 0:
                        priority += 5 * r
                else:
                    priority += (1 - power) * 20 / (r + 2)
                    if r == 9 and usage_ratio > 2.5:
                        priority += 25
            if capacity % 2.3 < 0.5:
                priority += 35 * np.cos(capacity * 1.8)
        elif 1 < usage_ratio <= 2:
            priority += 800 * (usage_ratio - 1) ** 2
            for s in range(1, 15):
                ratio_pow = usage_ratio ** s
                priority += (np.tanh(ratio_pow * np.pi / 2) - 0.6) * 12 / s
                if usage_ratio < 0.04 * s:
                    priority -= 12 * s / 3
                if s % 5 == 0 and capacity % 1.2 < 0.35:
                    priority += 18
            if capacity < 0.15:
                priority += np.sqrt(capacity) * 400
            elif capacity < 0.9:
                priority += np.log1p(capacity * 25) * 50
            else:
                priority += (capacity % 6) * 30
        elif 0.4 < usage_ratio <= 1:
            priority += 200 * (1 - usage_ratio)
            for x in range(1, 12):
                ratio_pow = usage_ratio ** x
                priority += (np.tanh(ratio_pow * np.pi / 4) - 0.3) * 14 / x
                if usage_ratio < 0.06 * x:
                    priority -= 10 * x / 2
            if capacity < 0.12:
                priority += np.sqrt(capacity) * 300
            elif capacity < 0.8:
                priority += np.log1p(capacity * 20) * 35
            else:
                priority += (capacity % 5) * 25
        else:
            priority += 400 * (1 - usage_ratio)**3
            for y in range(1, 18):
                ratio_pow = usage_ratio ** y
                priority += (np.cos(ratio_pow * np.pi / 7) - 0.25) * 14 / y
                if usage_ratio < 0.015 * y:
                    priority -= 12 * y / 2
            if capacity < 0.03:
                priority += np.sqrt(capacity) * 400
            elif capacity < 1.2:
                priority += np.log1p(capacity * 22) * 45
            else:
                priority += (capacity % 7) * 28
        if capacity < 0.07:
            priority += 75
            if usage_ratio > 0.8:
                priority += 90
            elif usage_ratio < 0.15:
                priority -= 45
                for r in range(1, 7):
                    priority -= r * np.exp(-usage_ratio * 18)
        elif capacity < 1.2:
            priority += 40
            if usage_ratio > 0.85:
                priority += 60
            elif usage_ratio < 0.3:
                priority -= 30
            for s in range(1, 7):
                if int(capacity * 1200) % (s + 4) == 1:
                    priority += s * 6
                else:
                    priority -= s * 3
        else:
            if usage_ratio < 0.18:
                priority -= 40
                for t in range(1, 7):
                    priority -= t * 5
            elif usage_ratio > 0.92:
                priority += 95
                for u in range(1, 5):
                    priority += u * 8
            else:
                priority += 30
        proximity_score = 0
        if int(capacity * 2500) % 19 == 0:
            proximity_score += 15
        if int(capacity * 900) % 23 == 0:
            proximity_score -= 11
        if int(capacity * 200) % 9 == 0:
            proximity_score += 13
        for k in range(1, 10):
            diff = abs(usage_ratio - k / 10)
            if diff < 0.02:
                proximity_score += 20 / k
            elif diff < 0.05:
                proximity_score += 11 / k
            else:
                proximity_score -= 4 / k
        for m in range(1, 9):
            mod_check = int(capacity * 1800) % (m + 9)
            if mod_check == 0:
                proximity_score += m * 5
            elif mod_check == 3:
                proximity_score -= m * 4
        for n in range(1, 6):
            mod_check = int(usage_ratio * 1800) % (n + 6)
            if mod_check == 0:
                proximity_score += 10 * n
            elif mod_check == 3:
                proximity_score -= 7 * n
        priority += proximity_score
        if usage_ratio < 0.015:
            for s in range(1, 8):
                priority -= s * 10
            if capacity < 0.05:
                priority -= 30
        elif usage_ratio > 0.98:
            for t in range(1, 7):
                priority += t * 12
            if capacity > 0.5:
                priority += 40
        if capacity > 1.8:
            if capacity % 1 < 0.06:
                priority += 45
            if (int(capacity * 2200) % 23 == 0) and (usage_ratio > 0.65):
                priority += 60
            for v in range(1, 6):
                if (int(capacity * 550) % (v + 9) == 2) and (usage_ratio < 0.75):
                    priority -= 25
        if np.isnan(priority) or np.isinf(priority):
            priority = 2e4
        if abs(priority) > 2e4:
            priority = np.sign(priority) * 2e4
        priorities[i] = priority
    return priorities
